#include <mutex>
#include <condition_variable>
#include <queue>

std::mutex mtx;
std::condition_variable cv;
std::queue<int> q;

void producer() {
    std::lock_guard<std::mutex> lock(mtx);
    q.push(42);
    cv.notify_one();
}

int consumer() {
    std::unique_lock<std::mutex> lock(mtx);
    cv.wait(lock, [] { return !q.empty(); });
    int val = q.front();
    q.pop();
    return val;
}

int main() {
    producer();
    return consumer();
}

#include <mutex>
#include <condition_variable>

std::mutex mtx;
std::condition_variable cv;
bool ready = false;

int main() {
    // notify_one: يُيقظ خيطًا واحدًا فقط — أنسب لمنتج-مستهلك
    // notify_all: يُيقظ كل الخيوط — أنسب لمرحلة متعددة (barrier)
    std::unique_lock<std::mutex> lock(mtx);
    ready = true;
    cv.notify_all();
    return 0;
}

